import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { DashboardWebSocket } from '@/services/websocket'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<DashboardWebSocket | null>(null)
  const connected = ref(false)
  const eventHistory = ref<Array<{ event: string; data: any; timestamp: Date }>>([])

  const connectionStatus = computed(() => {
    return connected.value ? 'connected' : 'disconnected'
  })

  function connect(url: string) {
    if (!ws.value) {
      ws.value = new DashboardWebSocket()
      ws.value.connect(url)

      ws.value.on('open', () => {
        connected.value = true
      })

      ws.value.on('close', () => {
        connected.value = false
      })
    }
  }

  function on(event: string, handler: Function) {
    ws.value?.on(event, handler)

    // 记录事件历史
    const wrappedHandler = (data: any) => {
      eventHistory.value.push({
        event,
        data,
        timestamp: new Date()
      })

      // 限制历史记录数量
      if (eventHistory.value.length > 1000) {
        eventHistory.value.shift()
      }

      handler(data)
    }

    ws.value?.on(event, wrappedHandler)
  }

  function send(event: string, data: any) {
    ws.value?.send({ event, data })
  }

  function disconnect() {
    ws.value?.disconnect()
    ws.value = null
    connected.value = false
  }

  return {
    ws,
    connected,
    connectionStatus,
    eventHistory,
    connect,
    on,
    send,
    disconnect
  }
})
```

